   555→// Helper: Evaluate short answer
   556→async function evaluateShortAnswer(question, answer, rubric) {
   557→  const prompt = `Evaluate this short answer response to a technical assessment question.
   558→
   559→Question: ${question}
   560→
   561→Student's Answer: ${answer}
   562→
   563→Expected concepts: ${rubric}
   564→
   565→Return ONLY valid JSON (no markdown, no code blocks):
